      trigger_keywords: ["budget", "encheres", "lancer", "deployer", "couper", "scaler", "ROAS", "Meta", "Google Ads", "campagne"]
    }
  },

  // ─────────────────────────────────────────────────────────────────────────
  // UI COMPONENTS REGISTRY
  // ─────────────────────────────────────────────────────────────────────────
  ui_components: {
    KPI_CARD: "KPI_CARD",
    CHART_WIDGET: "CHART_WIDGET",
    AD_PREVIEW: "AD_PREVIEW",
    BATTLE_CARD: "BATTLE_CARD",
    WEB_SEARCH_RESULT: "WEB_SEARCH_RESULT",
    COMPETITOR_INTEL: "COMPETITOR_INTEL",
    CAMPAIGN_TABLE: "CAMPAIGN_TABLE",
    ACTION_BUTTONS: "ACTION_BUTTONS",
    LOADING: "LOADING",
    ERROR: "ERROR",
    APPROVAL_REQUEST: "APPROVAL_REQUEST"
  }
};

// Ajouter le message utilisateur entrant
globalContext.user_input = {
  message: $input.first().json.body?.message || $input.first().json.message || "",
  session_id: $input.first().json.body?.session_id || `session_${Date.now()}`,
  timestamp: new Date().toISOString()
};

return [{ json: globalContext }];

// ============================================================================
// FORMAT UI RESPONSE - Agency Killer V4 (Cloud Native)
// ============================================================================
// Formate la reponse de l'AI Agent pour respecter le UI Schema.
// Integre les reponses des agents specialistes.
// ============================================================================

const context = $('Inject System Prompt').item.json;
const agentOutput = $input.first().json;

// ─────────────────────────────────────────────────────────────────────────
// HELPER: Detecter quel agent a ete appele
// ─────────────────────────────────────────────────────────────────────────
function detectCalledAgent(output) {
  if (output.analyst_response) return { id: 'analyst', name: 'The Analyst', response: output.analyst_response };
  if (output.strategist_response) return { id: 'strategist', name: 'The Strategist', response: output.strategist_response };
  if (output.creative_response) return { id: 'creative', name: 'The Creative', response: output.creative_response };
  if (output.trader_response) return { id: 'trader', name: 'The Trader', response: output.trader_response };
  return null;
}

// ─────────────────────────────────────────────────────────────────────────
// HELPER: Construire les composants UI
// ─────────────────────────────────────────────────────────────────────────
function buildUIComponents(calledAgent, rawOutput) {
  const components = [];

  // Si un agent a ete appele, utiliser sa reponse
  if (calledAgent && calledAgent.response) {
    try {
      const agentResponse = typeof calledAgent.response === 'string' 
        ? JSON.parse(calledAgent.response) 
        : calledAgent.response;

      // Transmettre les composants UI de l'agent
      if (agentResponse.ui_components) {
        return agentResponse.ui_components;
      }
      if (agentResponse.ui_component) {
        return [{
          type: agentResponse.ui_component,
          data: agentResponse,
          layout: { width: 'full', order: 1 }
        }];
      }
    } catch (e) {
      // Fallback si parsing echoue
    }
  }

  // Menu par defaut si aucun agent appele
  components.push({
    type: 'ACTION_BUTTONS',
    data: {
      layout: 'grid',
      actions: [
        {
          id: 'menu_analyst',
          label: 'Analyser mes performances',
          icon: 'chart-line',
          action_type: 'message',
          variant: 'secondary',
          payload: { message: 'Montre-moi mon bilan de performance' }
        },
        {
          id: 'menu_strategist',
          label: 'Veille concurrentielle',
          icon: 'search',
          action_type: 'message',
          variant: 'secondary',
          payload: { message: 'Analyse mes concurrents' }
        },
        {
          id: 'menu_creative',
          label: 'Creer une publicite',
          icon: 'palette',
          action_type: 'message',
          variant: 'secondary',
          payload: { message: 'Cree une banniere publicitaire' }
        },
        {
          id: 'menu_trader',
          label: 'Gerer mes campagnes',
          icon: 'currency-euro',
          action_type: 'message',
          variant: 'secondary',
          payload: { message: 'Optimise mes campagnes actives' }
        }
      ]
    },
    layout: { width: 'full', order: 1 }
  });

  return components;
}

// ─────────────────────────────────────────────────────────────────────────
// MAIN: Construire la reponse UI
// ─────────────────────────────────────────────────────────────────────────
const calledAgent = detectCalledAgent(agentOutput);
const chatContent = agentOutput.output || agentOutput.text || '';

const uiResponse = {
  // THOUGHT PROCESS
  thought_process: {
    step: calledAgent ? 'Specialist Delegation' : 'Intent Classification',
    reasoning: calledAgent 
      ? `Demande deleguee a ${calledAgent.name} pour traitement specialise.`
      : 'Presentation du menu principal ou reponse directe.',
    tools_used: calledAgent ? [`call_${calledAgent.id}`] : ['menu_display'],
    data_sources: ['brand_memory', 'specialists_registry'],
    confidence: calledAgent ? 0.92 : 0.75,
    agent_called: calledAgent?.id || null
  },

  // CHAT MESSAGE
  chat_message: {
    content: chatContent || '**Bienvenue dans The Hive.**\n\nJe suis votre Directeur de Strategie. Comment puis-je vous aider ?',
    tone: calledAgent ? 'suggestion' : 'neutral',
    follow_up_questions: calledAgent 
      ? [
          'Voir plus de details ?',
          'Lancer une autre analyse ?',
          'Exporter les resultats ?'
        ]
      : [
          'Quel est mon ROAS actuel ?',
          'Analyse mes concurrents',
          'Cree une pub Meta'
        ],
    delegated_to: calledAgent?.name || null
  },

  // UI COMPONENTS
  ui_components: buildUIComponents(calledAgent, agentOutput),

  // METADATA
  meta: {
    agent_id: 'orchestrator',
    version: 'v4.1_wired',
    timestamp: new Date().toISOString(),
    request_id: `req_${Date.now()}`,
    session_id: context.user_input.session_id,
    brand_id: context.brand_memory.identity.name,
    specialist_called: calledAgent?.id || null,
    processing_time_ms: Date.now() - new Date(context.user_input.timestamp).getTime()
  }
};

return [{ json: uiResponse }];
